const Btn=({children,onClick,v="primary",icon,small,style:s,disabled})=>{const base={display:"inline-flex",alignItems:"center",gap:7,border:"none",cursor:disabled?"not-allowed":"pointer",fontFamily:fb,fontWeight:600,borderRadius:8,fontSize:small?12:13,padding:small?"6px 14px":"10px 20px",opacity:disabled?.5:1};const vs={primary:{background:T.ac,color:"#FFF"},danger:{background:T.dnD,color:T.dn,border:"1px solid "+T.dn+"25"},success:{background:T.sc,color:"#FFF"},ghost:{background:"transparent",color:T.mt,border:"1px solid "+T.bd}};return<button onClick={disabled?undefined:onClick} style={{...base,...vs[v],...s}}>{icon&&<Icon name={icon} size={small?14:16} color={v==="primary"||v==="success"?"#FFF":vs[v]?.color||T.mt}/>}{children}</button>;};
const Inp=({label,value,onChange,placeholder,type="text",textarea,select,options,file,half})=>(<div style={{marginBottom:14,flex:half?"1":"auto",minWidth:half?180:"auto"}}>{label&&<label style={{display:"block",fontSize:11,color:T.mt,marginBottom:5,fontFamily:fm,letterSpacing:"0.04em",textTransform:"uppercase",fontWeight:500}}>{label}</label>}{select?<select value={value} onChange={e=>onChange(e.target.value)} style={{width:"100%",padding:"9px 12px",background:T.bg,border:"1px solid "+T.bd,borderRadius:8,color:T.tx,fontSize:14,fontFamily:fb,outline:"none"}}>{options.map(o=><option key={o.v} value={o.v}>{o.l}</option>)}</select>:file?<div style={{border:"2px dashed "+T.bd,borderRadius:8,padding:16,textAlign:"center",cursor:"pointer",background:T.bg}}><Icon name="upload" size={20} color={T.dm}/><div style={{fontSize:12,color:T.mt,marginTop:4}}>PDF, JPG, PNG, ZIP (до 25МБ)</div></div>:textarea?<textarea value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder} rows={3} style={{width:"100%",padding:"9px 12px",background:T.bg,border:"1px solid "+T.bd,borderRadius:8,color:T.tx,fontSize:14,fontFamily:fb,outline:"none",resize:"vertical",boxSizing:"border-box"}}/>:<input type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder} style={{width:"100%",padding:"9px 12px",background:T.bg,border:"1px solid "+T.bd,borderRadius:8,color:T.tx,fontSize:14,fontFamily:fb,outline:"none",boxSizing:"border-box"}}/>}</div>);
