const Tbl=({cols,data,onRow})=>(<div style={{overflowX:"auto"}}><table style={{width:"100%",borderCollapse:"collapse",fontSize:13,fontFamily:fb}}><thead><tr>{cols.map(c=><th key={c.k} style={{textAlign:"left",padding:"9px 10px",fontSize:10,fontFamily:fm,color:T.dm,borderBottom:"2px solid "+T.bd,background:T.bg,textTransform:"uppercase",letterSpacing:"0.06em"}}>{c.l}</th>)}</tr></thead><tbody>{data.map((r,i)=><tr key={i} onClick={()=>onRow&&onRow(r)} style={{cursor:onRow?"pointer":"default"}} onMouseEnter={e=>e.currentTarget.style.background=T.hv} onMouseLeave={e=>e.currentTarget.style.background=""}>{cols.map(c=><td key={c.k} style={{padding:"9px 10px",borderBottom:"1px solid "+T.bdL}}>{c.r?c.r(r[c.k],r):r[c.k]}</td>)}</tr>)}</tbody></table></div>);

const BarChart=({data,color,height=100,label})=>{const max=Math.max(...data.map(d=>d.v),1);const bw=Math.min(36,Math.floor(240/data.length));const w=data.length*(bw+6)+16;return<div style={{background:T.sf,border:"1px solid "+T.bd,borderRadius:10,padding:"14px 16px",flex:1,minWidth:220}}>{label&&<div style={{fontSize:11,color:T.mt,fontFamily:fm,textTransform:"uppercase",marginBottom:10}}>{label}</div>}<svg width="100%" height={height} viewBox={"0 0 "+w+" "+height} style={{display:"block"}}>{data.map((d,i)=>{const h2=Math.max((d.v/max)*(height-28),2);const x=8+i*(bw+6);return<g key={i}><rect x={x} y={height-h2-16} width={bw} height={h2} rx={2} fill={color} opacity={0.75}/><text x={x+bw/2} y={height-2} textAnchor="middle" fontSize="9" fill={T.mt} fontFamily="sans-serif">{d.l}</text><text x={x+bw/2} y={height-h2-20} textAnchor="middle" fontSize="8" fill={T.ts} fontWeight="600" fontFamily="sans-serif">{d.v}</text></g>})}</svg></div>};
const PieChart=({segments,size=90,label})=>{const total=segments.reduce((a,s)=>a+s.v,0)||1;let cum=0;const arcs=segments.map(s=>{const st=cum/total*360;cum+=s.v;return{...s,start:st,end:cum/total*360};});const r=size/2-4,cx=size/2,cy=size/2;const ptc=(deg)=>({x:cx+r*Math.cos((deg-90)*Math.PI/180),y:cy+r*Math.sin((deg-90)*Math.PI/180)});return<div style={{background:T.sf,border:"1px solid "+T.bd,borderRadius:10,padding:"14px 16px",minWidth:190}}>{label&&<div style={{fontSize:11,color:T.mt,fontFamily:fm,textTransform:"uppercase",marginBottom:10}}>{label}</div>}<div style={{display:"flex",alignItems:"center",gap:14}}><svg width={size} height={size} viewBox={"0 0 "+size+" "+size}>{arcs.map((a,i)=>{if(a.v===0)return null;const lg=a.end-a.start>180?1:0;const s=ptc(a.start),e=ptc(a.end-0.5);return<path key={i} d={"M"+cx+","+cy+" L"+s.x+","+s.y+" A"+r+","+r+" 0 "+lg+" 1 "+e.x+","+e.y+" Z"} fill={a.color} opacity={0.85}/>})}</svg><div>{segments.map((s,i)=><div key={i} style={{display:"flex",alignItems:"center",gap:6,marginBottom:4}}><span style={{width:8,height:8,borderRadius:3,background:s.color,flexShrink:0}}/><span style={{fontSize:12,color:T.ts}}>{s.label}: <strong>{s.v}</strong></span></div>)}</div></div></div>};

