const PASSES_INIT=Array.from({length:30},(_,i)=>{const st=i<6?"pending":i<20?"approved":"rejected";return{id:"#"+String(200+i),type:i%4===0?"vehicle":"visitor",requester:names[i%names.length],dept:depts[i%depts.length],visitor:names[(i+5)%names.length],iin:String(850000000000+i*111111),purpose:purposes[i%purposes.length],host:names[(i+10)%names.length],hostPhone:"+7 70"+i%10+" "+String(100+i),floor:(i%5+1)+"",dateFrom:"0"+(1+i%5)+".05.2026",dateTo:String(5+i%15)+".05.2026",status:st,sub:SUBS[i%4],approver:names[(i+15)%names.length],tmc:i%3===0?["Ноутбук","Сумка с инструментами"]:i%3===1?["Мультиметр"]:[]};});
const INSPECTIONS=Array.from({length:30},(_,i)=>{const isPer=i%4===0;return{id:i+1,plate:isPer?"—":plates[i%plates.length],driver:names[i%names.length],vtype:isPer?"—":vtypes[i%vtypes.length],inspType:isPer?"person":"vehicle",time:String(7+Math.floor(i/4)).padStart(2,"0")+":"+String(i*7%60).padStart(2,"0"),post:"КПП-"+(i%3+1),status:i===5||i===12?"violation":"passed",sub:SUBS[i%4],notes:i===5?"Перегруз":i===12?"Незадекл. груз":"Без замечаний"};});
