const DOCS=Array.from({length:20},(_,i)=>{const cats=["Приказы","Инструкции","Акты","Журналы"];return{id:i+1,name:["Приказ №"+String(130+i),"Инструкция — Досмотр ТС","Акт проверки КПП-"+(i%3+1),"Журнал выдачи ключей","Приказ — Безопасность работ","Инструкция — Действия при ЧС","Акт инвентаризации СИЗ","Журнал обхода периметра"][i%8],category:cats[i%4],date:String(28-i%28).padStart(2,"0")+".04.2026",author:names[i%names.length],status:i<16?"active":"archive",sub:SUBS[i%4]};});
