export default function App(){
    const [auth,setAuth]=useState(null);
    const [authStep,setAuthStep]=useState("form");
    const [page,setPage]=useState("dashboard");
    const [panel,setPanel]=useState(null);
    const [toast,setToast]=useState(null);
    const [passes,setPasses]=useState(PASSES_INIT);
    const [collapsed,setCol]=useState(false);
    const [kppView,setKppView]=useState("main");
    const [kppWait,setKppWait]=useState(VW);
    const [kppInside,setKppInside]=useState(VI);
    const [kppJournal,setKppJournal]=useState(JOURNAL);
    const [approvers,setApprovers]=useState([{id:1,name:"Руководитель подразделения",role:"Инициатор"},{id:2,name:"Служба безопасности",role:"Согласующий"},{id:3,name:"Начальник СБ",role:"Утверждающий"}]);
    const [showAddStep,setShowAddStep]=useState(false);
    const [syncing,setSyncing]=useState(false);
    const [guardsData,setGuardsData]=useState(GUARDS);
    const doSync=()=>{setSyncing(true);setTimeout(()=>{setSyncing(false);setGuardsData(prev=>{const a=[...prev];for(let i=a.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]];}return a.map((g,idx)=>({...g,status:["on_duty","on_duty","off_duty","on_duty","vacation","sick"][idx%6]}));});showToast("Синхронизация с 1С завершена — данные обновлены");},10000);}; // main | journal
    const showToast=(m,t="success")=>{setToast({m,t});setTimeout(()=>setToast(null),3000);};
    const approvPass=(id)=>{setPasses(p=>p.map(x=>x.id===id?{...x,status:"approved"}:x));showToast("Заявка "+id+" согласована");};
    const rejectPass=(id)=>{setPasses(p=>p.map(x=>x.id===id?{...x,status:"rejected"}:x));showToast("Заявка "+id+" отклонена","danger");};
    const CSS=`@import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&family=IBM+Plex+Mono:wght@400;500;600;700&family=Outfit:wght@400;500;600;700;800&display=swap');*{box-sizing:border-box;margin:0;padding:0}::-webkit-scrollbar{width:6px}::-webkit-scrollbar-thumb{background:${T.bd};border-radius:3px}@keyframes slideRight{from{transform:translateX(100%)}to{transform:translateX(0)}}@keyframes fadeIn{from{opacity:0}to{opacity:1}}@keyframes spin{from{transform:rotate(0deg)}to{transform:rotate(360deg)}}select option{background:${T.sf}}input::placeholder,textarea::placeholder{color:${T.dm}}`;
    const Toast=()=>toast?<div style={{position:"fixed",bottom:18,right:18,zIndex:3000,background:"#FFF",border:"1px solid "+(toast.t==="danger"?T.dn:T.sc)+"30",borderLeft:"4px solid "+(toast.t==="danger"?T.dn:T.sc),borderRadius:10,padding:"12px 18px",display:"flex",alignItems:"center",gap:8,boxShadow:"0 8px 32px rgba(30,26,22,0.15)",animation:"fadeIn 0.3s"}}><Icon name={toast.t==="danger"?"x":"check"} size={15} color={toast.t==="danger"?T.dn:T.sc}/><span style={{fontSize:13,fontWeight:600}}>{toast.m}</span></div>:null;
    /* ID card preview component */
    const IDCardPreview=({name})=>(<div style={{border:"2px solid "+T.bd,borderRadius:10,padding:14,background:T.bg,marginBottom:14}}><div style={{display:"flex",alignItems:"center",gap:10,marginBottom:8}}><Icon name="idcard" size={18} color={T.sl}/><span style={{fontSize:12,fontWeight:700,color:T.sl,fontFamily:fm,textTransform:"uppercase"}}>Документ посетителя</span></div><div style={{background:T.sf,borderRadius:8,padding:12,display:"flex",gap:14,border:"1px solid "+T.bdL}}><div style={{width:80,height:100,borderRadius:6,background:"linear-gradient(135deg,#dde4ec,#c8d0dc)",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}><Icon name="user" size={32} color="#8899aa"/></div><div style={{flex:1}}><div style={{fontSize:9,color:T.dm,fontFamily:fm,marginBottom:4}}>УДОСТОВЕРЕНИЕ ЛИЧНОСТИ</div><div style={{fontSize:9,color:T.dm,fontFamily:fm,marginBottom:2}}>ЖЕКЕ КУӘЛІК</div><div style={{height:1,background:T.bd,margin:"6px 0"}}/><div style={{fontSize:14,fontWeight:700,color:T.tx,marginBottom:6}}>{name}</div><div style={{fontSize:11,color:T.mt}}>ИИН: 850412******</div><div style={{fontSize:11,color:T.mt}}>Выдан: МВД РК</div><div style={{fontSize:11,color:T.mt}}>Действителен до: 12.2030</div></div></div></div>);

    // ═══ LOGIN SELECT ═══
    if(!auth) return(<div style={{height:"100vh",background:"linear-gradient(135deg,#2C2420,#1E1A16)",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:fb}}><style>{CSS}</style><div style={{display:"flex",gap:40}}>{[{k:"main",icon:"shield",color:T.ac,title:"Вход для СБ / ИТР",sub:"Заявки, согласование, аналитика"},{k:"kpp",icon:"user",color:T.sc,title:"Вход для КПП",sub:"Регистрация входа / выхода"}].map(c=><div key={c.k} onClick={()=>setAuth(c.k)} style={{width:300,background:"rgba(255,255,255,0.04)",border:"1px solid rgba(255,255,255,0.08)",borderRadius:20,padding:36,cursor:"pointer",textAlign:"center",transition:"all 0.3s"}} onMouseEnter={e=>{e.currentTarget.style.background=c.color+"14";e.currentTarget.style.borderColor=c.color+"50";}} onMouseLeave={e=>{e.currentTarget.style.background="rgba(255,255,255,0.04)";e.currentTarget.style.borderColor="rgba(255,255,255,0.08)";}}><img src={LOGO} width={56} height={56} style={{objectFit:"contain",marginBottom:16}} alt=""/><div style={{fontSize:20,fontWeight:800,color:"#F0EBE4",fontFamily:fd,marginBottom:6}}>Polymetal СБ</div><div style={{fontSize:12,color:T.st,marginBottom:20}}>{c.k==="main"?"Панель управления":"Рабочее место охранника"}</div><div style={{width:52,height:52,borderRadius:14,background:c.color+"20",border:"2px solid "+c.color+"40",display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 14px"}}><Icon name={c.icon} size={24} color={c.color}/></div><div style={{fontSize:15,fontWeight:700,color:c.color}}>{c.title}</div><div style={{fontSize:12,color:T.st,marginTop:4}}>{c.sub}</div></div>)}</div></div>);

    // ═══ LOGIN FORM ═══
    if(authStep==="form") return(<div style={{height:"100vh",background:auth==="kpp"?"linear-gradient(135deg,#1a2e1f,#1E1A16)":"linear-gradient(135deg,#2C2420,#1E1A16)",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:fb}}><style>{CSS}</style><div style={{width:380,background:"rgba(255,255,255,0.03)",border:"1px solid rgba(255,255,255,0.08)",borderRadius:20,padding:36,textAlign:"center"}}><img src={LOGO} width={48} height={48} style={{objectFit:"contain",marginBottom:14}} alt=""/><div style={{fontSize:18,fontWeight:800,color:"#F0EBE4",fontFamily:fd,marginBottom:3}}>Polymetal СБ</div><div style={{fontSize:12,color:T.st,marginBottom:28}}>{auth==="kpp"?"Рабочее место охранника КПП":"Панель управления СБ"}</div><div style={{marginBottom:14}}><input placeholder="Логин" style={{width:"100%",padding:"13px 16px",background:"rgba(255,255,255,0.06)",border:"1px solid rgba(255,255,255,0.12)",borderRadius:10,color:"#F0EBE4",fontSize:15,fontFamily:fb,outline:"none",boxSizing:"border-box"}}/></div><div style={{marginBottom:22}}><input type="password" placeholder="Пароль" style={{width:"100%",padding:"13px 16px",background:"rgba(255,255,255,0.06)",border:"1px solid rgba(255,255,255,0.12)",borderRadius:10,color:"#F0EBE4",fontSize:15,fontFamily:fb,outline:"none",boxSizing:"border-box"}}/></div><button onClick={()=>setAuthStep("app")} style={{width:"100%",padding:"13px",borderRadius:10,border:"none",background:auth==="kpp"?T.sc:T.ac,color:"#FFF",fontSize:15,fontWeight:700,fontFamily:fd,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",gap:8}}><Icon name="login" size={18} color="#FFF"/> Войти</button><button onClick={()=>setAuth(null)} style={{background:"none",border:"none",color:T.st,fontSize:12,marginTop:14,cursor:"pointer",fontFamily:fb}}>← Выбрать другой вход</button></div></div>);

    // ═══ KPP VIEW ═══
    if(auth==="kpp") return(<div style={{display:"flex",flexDirection:"column",height:"100vh",background:T.bg,fontFamily:fb,overflow:"hidden"}}><style>{CSS}</style>
        <div style={{height:52,background:"#2C2420",display:"flex",alignItems:"center",justifyContent:"space-between",padding:"0 20px",flexShrink:0}}><div style={{display:"flex",alignItems:"center",gap:10}}><img src={LOGO} width={28} height={28} style={{objectFit:"contain"}} alt=""/><div><div style={{fontSize:14,fontWeight:800,color:"#F0EBE4",fontFamily:fd}}>Polymetal СБ</div><div style={{fontSize:9,color:T.st,fontFamily:fm}}>КПП-1 • ОХРАННИК</div></div></div><div style={{display:"flex",alignItems:"center",gap:12}}>
            <button onClick={()=>setKppView(kppView==="journal"?"main":"journal")} style={{display:"flex",alignItems:"center",gap:6,padding:"6px 14px",borderRadius:8,border:kppView==="journal"?"2px solid "+T.ac:"1px solid rgba(255,255,255,0.15)",background:kppView==="journal"?T.ac+"20":"rgba(255,255,255,0.06)",color:kppView==="journal"?T.ac:"#ccc",cursor:"pointer",fontSize:13,fontFamily:fb,fontWeight:600}}><Icon name="book" size={15} color={kppView==="journal"?T.ac:"#ccc"}/>{kppView==="journal"?"Главная":"Журнал"}</button>
            <div style={{display:"flex",alignItems:"center",gap:4,padding:"3px 7px",background:T.scD,borderRadius:5}}><Dot color={T.sc}/><span style={{fontSize:10,color:T.sc,fontFamily:fm,fontWeight:600}}>ОНЛАЙН</span></div><span style={{fontSize:20,fontWeight:800,color:"#F0EBE4",fontFamily:fm}}>14:32</span><button onClick={()=>{setAuth(null);setAuthStep("form");setKppView("main");}} style={{background:"rgba(255,255,255,0.06)",border:"1px solid rgba(255,255,255,0.1)",borderRadius:7,cursor:"pointer",padding:5,display:"flex"}}><Icon name="logout" size={15} color={T.st}/></button></div></div>
        {kppView==="main"?<div style={{flex:1,display:"flex",gap:14,padding:14,overflow:"hidden"}}>
                <div style={{flex:1,display:"flex",flexDirection:"column",background:T.sf,border:"2px solid "+T.wn+"30",borderRadius:12,overflow:"hidden"}}><div style={{padding:"12px 16px",background:T.wnD,borderBottom:"2px solid "+T.wn+"20",display:"flex",alignItems:"center",gap:8}}><Icon name="calendar" size={16} color={T.wn}/><span style={{fontSize:15,fontWeight:700,fontFamily:fd,color:T.wn}}>Ожидают прохода</span><Badge color={T.wn}>{kppWait.length}</Badge></div><div style={{flex:1,overflow:"auto",padding:6}}>{kppWait.map(v=><div key={v.id} style={{background:T.sf,border:"1px solid "+T.bd,borderRadius:9,padding:"10px 12px",marginBottom:6,display:"flex",alignItems:"center",gap:10,cursor:"pointer"}} onClick={()=>setPanel({type:"kppEntry",data:v})}><div style={{width:36,height:36,borderRadius:9,background:T.acD,border:"1px solid "+T.ac+"25",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}><Icon name="user" size={16} color={T.ac}/></div><div style={{flex:1,minWidth:0}}><div style={{fontSize:14,fontWeight:700}}>{v.name}</div><div style={{fontSize:11,color:T.mt}}>{v.company}</div>{v.tmc.length>0&&<div style={{fontSize:10,color:T.ac,fontWeight:600}}>ТМЦ: {v.tmc.join(", ")}</div>}</div><Btn v="success" icon="login" small onClick={e=>{e.stopPropagation();setPanel({type:"kppEntry",data:v});}}>Вход</Btn></div>)}</div></div>
                <div style={{flex:1,display:"flex",flexDirection:"column",background:T.sf,border:"2px solid "+T.sc+"30",borderRadius:12,overflow:"hidden"}}><div style={{padding:"12px 16px",background:T.scD,borderBottom:"2px solid "+T.sc+"20",display:"flex",alignItems:"center",gap:8}}><Icon name="shield" size={16} color={T.sc}/><span style={{fontSize:15,fontWeight:700,fontFamily:fd,color:T.sc}}>На территории</span><Badge color={T.sc}>{kppInside.length}</Badge></div><div style={{flex:1,overflow:"auto",padding:6}}>{kppInside.map(v=><div key={v.id} style={{background:T.sf,border:"1px solid "+T.bd,borderRadius:9,padding:"10px 12px",marginBottom:6,display:"flex",alignItems:"center",gap:10,cursor:"pointer"}} onClick={()=>setPanel({type:"kppExit",data:v})}><div style={{width:36,height:36,borderRadius:9,background:T.scD,border:"1px solid "+T.sc+"25",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}><Icon name="user" size={16} color={T.sc}/></div><div style={{flex:1,minWidth:0}}><div style={{fontSize:14,fontWeight:700}}>{v.name}</div><div style={{fontSize:11,color:T.mt}}>{v.company} • с {v.timeIn}</div>{v.tmc.length>0&&<div style={{fontSize:10,color:T.sc,fontWeight:600}}>ТМЦ: {v.tmc.join(", ")}</div>}</div><Btn v="danger" icon="logout" small onClick={e=>{e.stopPropagation();setPanel({type:"kppExit",data:v});}}>Выход</Btn></div>)}</div></div>
            </div>
            :<div style={{flex:1,overflow:"auto",padding:14}}>
                <div style={{background:T.sf,border:"1px solid "+T.bd,borderRadius:12}}><div style={{padding:"14px 18px",borderBottom:"1px solid "+T.bd,display:"flex",alignItems:"center",gap:8}}><Icon name="book" size={18} color={T.sl}/><span style={{fontSize:16,fontWeight:700,fontFamily:fd}}>Журнал прохождений за сегодня</span><Badge color={T.sl}>{kppJournal.length}</Badge></div>
                    <Tbl cols={[{k:"name",l:"ФИО",r:v=><span style={{fontWeight:600}}>{v}</span>},{k:"company",l:"Организация"},{k:"purpose",l:"Цель"},{k:"timeIn",l:"Вход",r:v=><span style={{fontFamily:fm,color:T.sc}}>{v}</span>},{k:"timeOut",l:"Выход",r:v=><span style={{fontFamily:fm,color:T.dn}}>{v}</span>},{k:"tmc",l:"ТМЦ",r:v=>v.length>0?<Badge color={T.pu}>{v.join(", ")}</Badge>:<span style={{color:T.dm}}>—</span>}]} data={kppJournal} onRow={r=>setPanel({type:"journalDetail",data:r})}/>
                </div>
            </div>}
        {panel?.type==="kppEntry"&&<SlideOver title={"Вход — "+panel.data.name} onClose={()=>setPanel(null)} wide><div style={{border:"1px solid "+T.bd,borderRadius:8,padding:12,marginBottom:14,background:T.bg}}><div style={{display:"flex",alignItems:"center",gap:8,marginBottom:10}}><Icon name="idcard" size={16} color={T.sl}/><span style={{fontSize:11,fontWeight:700,color:T.sl,fontFamily:fm,textTransform:"uppercase"}}>Приложенный документ</span></div><img src={IDCARD} style={{width:"100%",borderRadius:6,border:"1px solid "+T.bdL}} alt="Удостоверение личности"/></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:14}}>{[["ФИО",panel.data.name],["Организация",panel.data.company],["Цель",panel.data.purpose],["Сопровождающий",panel.data.host],["Пропуск",panel.data.passId]].map(([l,v],i)=><div key={i}><div style={{fontSize:10,color:T.dm,fontFamily:fm,textTransform:"uppercase",marginBottom:2}}>{l}</div><div style={{fontSize:14,fontWeight:600}}>{v}</div></div>)}</div>{panel.data.tmc.length>0&&<div style={{background:T.acD,border:"1px solid "+T.ac+"25",borderRadius:8,padding:12,marginBottom:14}}><div style={{fontSize:11,fontWeight:700,color:T.ac,marginBottom:6}}>ТМЦ — подтвердите:</div>{panel.data.tmc.map((t,i)=><div key={i} style={{display:"flex",alignItems:"center",gap:6,padding:"6px 8px",background:T.sf,borderRadius:5,marginBottom:3}}><input type="checkbox" defaultChecked/><span style={{fontSize:13,fontWeight:600}}>{t}</span></div>)}</div>}<Inp label="Примечание" textarea placeholder="Комментарий..." value="" onChange={()=>{}}/><Btn v="success" icon="login" onClick={()=>{const d=panel.data;setKppWait(prev=>prev.filter(v=>v.id!==d.id));setKppInside(prev=>[{...d,timeIn:new Date().toLocaleTimeString("ru",{hour:"2-digit",minute:"2-digit"})},...prev]);setPanel(null);showToast("Вход "+d.name+" зарегистрирован");}} style={{width:"100%",justifyContent:"center",padding:"13px"}}>Зарегистрировать вход</Btn></SlideOver>}
        {panel?.type==="kppExit"&&<SlideOver title={"Выход — "+panel.data.name} onClose={()=>setPanel(null)} wide><div style={{border:"1px solid "+T.bd,borderRadius:8,padding:12,marginBottom:14,background:T.bg}}><div style={{display:"flex",alignItems:"center",gap:8,marginBottom:10}}><Icon name="idcard" size={16} color={T.sl}/><span style={{fontSize:11,fontWeight:700,color:T.sl,fontFamily:fm,textTransform:"uppercase"}}>Приложенный документ</span></div><img src={IDCARD} style={{width:"100%",borderRadius:6,border:"1px solid "+T.bdL}} alt="Удостоверение личности"/></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:14}}>{[["ФИО",panel.data.name],["Вход",panel.data.timeIn||"—"]].map(([l,v],i)=><div key={i}><div style={{fontSize:10,color:T.dm,fontFamily:fm,textTransform:"uppercase",marginBottom:2}}>{l}</div><div style={{fontSize:14,fontWeight:600}}>{v}</div></div>)}</div>{panel.data.tmc.length>0&&<div style={{background:T.scD,border:"1px solid "+T.sc+"25",borderRadius:8,padding:12,marginBottom:14}}><div style={{fontSize:11,fontWeight:700,color:T.sc,marginBottom:6}}>Проверка ТМЦ:</div>{panel.data.tmc.map((t,i)=><div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"8px 10px",background:T.sf,borderRadius:6,marginBottom:4,border:"1px solid "+T.sc+"15"}}><span style={{flex:1,fontSize:14,fontWeight:600}}>{t}</span><label style={{display:"flex",alignItems:"center",gap:5,cursor:"pointer"}}><input type="checkbox" defaultChecked/><span style={{fontSize:12,color:T.sc,fontWeight:600}}>Выносит</span></label><label style={{display:"flex",alignItems:"center",gap:5,cursor:"pointer"}}><input type="checkbox"/><span style={{fontSize:12,color:T.mt}}>Остаётся</span></label></div>)}</div>}<Inp label="Примечание" textarea placeholder="Комментарий..." value="" onChange={()=>{}}/><Btn v="danger" icon="logout" onClick={()=>{const d=panel.data;setKppInside(prev=>prev.filter(v=>v.id!==d.id));setKppJournal(prev=>[{...d,timeOut:new Date().toLocaleTimeString("ru",{hour:"2-digit",minute:"2-digit"})},...prev]);setPanel(null);showToast("Выход "+d.name+" зарегистрирован");}} style={{width:"100%",justifyContent:"center",padding:"13px"}}>Зарегистрировать выход</Btn></SlideOver>}
        {panel?.type==="journalDetail"&&<SlideOver title={"Запись — "+panel.data.name} onClose={()=>setPanel(null)}><div style={{border:"1px solid "+T.bd,borderRadius:8,padding:12,marginBottom:14,background:T.bg}}><div style={{display:"flex",alignItems:"center",gap:8,marginBottom:10}}><Icon name="idcard" size={16} color={T.sl}/><span style={{fontSize:11,fontWeight:700,color:T.sl,fontFamily:fm,textTransform:"uppercase"}}>Приложенный документ</span></div><img src={IDCARD} style={{width:"100%",borderRadius:6,border:"1px solid "+T.bdL}} alt="Удостоверение личности"/></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>{[["ФИО",panel.data.name],["Организация",panel.data.company],["Цель",panel.data.purpose],["Вход",panel.data.timeIn],["Выход",panel.data.timeOut],["ТМЦ",panel.data.tmc.length>0?panel.data.tmc.join(", "):"Нет"]].map(([l,v],i)=><div key={i}><div style={{fontSize:10,color:T.dm,fontFamily:fm,textTransform:"uppercase",marginBottom:2}}>{l}</div><div style={{fontSize:14,fontWeight:600}}>{v}</div></div>)}</div></SlideOver>}
        <Toast/>
    </div>);

    // ═══ MAIN SYSTEM PAGES ═══
    const navItems=[{id:"dashboard",label:"Дашборд",icon:"dashboard"},{id:"visitors",label:"Журнал посещений",icon:"visitors"},{id:"passes",label:"Пропуска",icon:"pass"},{id:"inspection",label:"Досмотр",icon:"car"},{id:"tmc",label:"ТМЦ",icon:"box"},{id:"cctv",label:"Видеонаблюдение",icon:"eye"},{id:"documents",label:"Документы",icon:"doc"},{id:"hr",label:"HR и график",icon:"hr"},{id:"settings",label:"Настройки",icon:"settings"}];

    const DashboardPage=()=>{const pPend=passes.filter(p=>p.status==="pending").length,pApp=passes.filter(p=>p.status==="approved").length,pRej=passes.filter(p=>p.status==="rejected").length;const iAuto=INSPECTIONS.filter(x=>x.inspType==="vehicle").length,iPer=INSPECTIONS.filter(x=>x.inspType==="person").length;const tIn=TMC_DATA.filter(t=>t.dir==="in").length,tOut=TMC_DATA.filter(t=>t.dir==="out").length;
        return(<div><h1 style={{fontSize:22,fontWeight:800,fontFamily:fd,margin:"0 0 14px"}}>Дашборд</h1>
            <div style={{display:"flex",gap:10,marginBottom:14,flexWrap:"wrap"}}>{[{icon:"visitors",label:"Посетители",value:kppInside.length+kppWait.length,sub:"На территории: "+kppInside.length,color:T.ac},{icon:"pass",label:"Заявки",value:passes.length,sub:"Ожидают: "+pPend,color:T.wn},{icon:"car",label:"Досмотры",value:INSPECTIONS.length,sub:"Нарушений: "+INSPECTIONS.filter(x=>x.status==="violation").length,color:T.sl},{icon:"shield",label:"Охранники",value:guardsData.filter(g=>g.status==="on_duty").length+"/"+guardsData.length,sub:"На смене",color:T.sc},{icon:"box",label:"ТМЦ",value:TMC_DATA.length,sub:"На территории: "+TMC_DATA.filter(t=>t.status==="on_site").length,color:T.pu}].map((s,i)=><div key={i} style={{background:T.sf,border:"1px solid "+T.bd,borderRadius:10,padding:"14px 18px",flex:1,minWidth:150,position:"relative",overflow:"hidden"}}><div style={{position:"absolute",top:0,left:0,right:0,height:3,background:s.color}}/><div style={{display:"flex",alignItems:"center",gap:7,marginBottom:6}}><div style={{width:28,height:28,borderRadius:7,background:s.color+"10",border:"1px solid "+s.color+"20",display:"flex",alignItems:"center",justifyContent:"center"}}><Icon name={s.icon} size={13} color={s.color}/></div><span style={{fontSize:10,color:T.mt,fontFamily:fm,textTransform:"uppercase"}}>{s.label}</span></div><div style={{fontSize:22,fontWeight:800,fontFamily:fd}}>{s.value}</div><div style={{fontSize:13,color:T.ts,marginTop:2}}>{s.sub}</div></div>)}</div>
            <div style={{display:"flex",gap:10,marginBottom:14}}>
                <BarChart data={[{l:"07",v:2},{l:"08",v:5},{l:"09",v:8},{l:"10",v:6},{l:"11",v:4},{l:"12",v:3},{l:"13",v:5},{l:"14",v:4}]} color={T.ac} label={"Посетители по часам"} height={100}/>
                <PieChart segments={[{label:"Одобрено",v:pApp,color:T.sc},{label:"Ожидает",v:pPend,color:T.wn},{label:"Отказ",v:pRej,color:T.dn}]} label="Заявки"/>
                <BarChart data={[{l:"07",v:1},{l:"08",v:4},{l:"09",v:6},{l:"10",v:3},{l:"11",v:2},{l:"12",v:1},{l:"13",v:3},{l:"14",v:2}]} color={T.pu} label={"ТМЦ движение"} height={100}/>
                <PieChart segments={[{label:"Авто",v:iAuto,color:T.sl},{label:"Физ.лица",v:iPer,color:T.ac}]} label="Досмотры"/>
            </div>
            <div style={{background:T.sf,border:"1px solid "+T.bd,borderRadius:10,padding:14}}><h3 style={{margin:"0 0 10px",fontSize:13,fontFamily:fd,fontWeight:700}}>Лента событий</h3>{[{time:"14:32",ev:"Въезд БелАЗ А123ВС — КПП-2",icon:"car",c:T.sl},{time:"14:28",ev:"Заявка #206 согласована",icon:"check",c:T.sc},{time:"14:15",ev:"Посетитель Иванов П.С. — вход",icon:"login",c:T.ac},{time:"14:02",ev:"Нарушение — незадекл. груз",icon:"eye",c:T.dn},{time:"13:55",ev:"Синхронизация с 1С",icon:"sync",c:T.sl}].map((e,i)=><div key={i} style={{display:"flex",alignItems:"center",gap:8,padding:"5px 0"}}><span style={{fontSize:10,fontFamily:fm,color:T.dm,width:36}}>{e.time}</span><div style={{width:22,height:22,borderRadius:5,background:e.c+"10",border:"1px solid "+e.c+"20",display:"flex",alignItems:"center",justifyContent:"center"}}><Icon name={e.icon} size={10} color={e.c}/></div><span style={{fontSize:12}}>{e.ev}</span></div>)}</div></div>);};

    const VisitorsPage=()=>{const [vf,setVf]=useState("all");const d=vf==="all"?VISITORS:VISITORS.filter(v=>v.status===vf);return(<div><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}><div><h1 style={{fontSize:22,fontWeight:800,fontFamily:fd,margin:0}}>Журнал посещений</h1><p style={{fontSize:12,color:T.mt,margin:"4px 0 0"}}>Электронный журнал КПП</p></div><Btn icon="plus">Новый посетитель</Btn></div><div style={{display:"flex",gap:5,marginBottom:12}}>{[{v:"all",l:"Все",c:VISITORS.length},{v:"inside",l:"На территории",c:VISITORS.filter(v=>v.status==="inside").length},{v:"left",l:"Покинули",c:VISITORS.filter(v=>v.status==="left").length}].map(f=><button key={f.v} onClick={()=>setVf(f.v)} style={{padding:"5px 14px",borderRadius:6,border:"1px solid "+(vf===f.v?T.ac:T.bd),background:vf===f.v?T.acD:T.sf,color:vf===f.v?T.ac:T.mt,cursor:"pointer",fontSize:12,fontFamily:fb,fontWeight:vf===f.v?600:400}}>{f.l} ({f.c})</button>)}</div><div style={{background:T.sf,border:"1px solid "+T.bd,borderRadius:10}}><Tbl cols={[{k:"name",l:"ФИО",r:(v,r)=><div><div style={{fontWeight:700}}>{v}</div><div style={{fontSize:11,color:T.dm}}>ИИН: {r.iin}</div></div>},{k:"company",l:"Организация"},{k:"purpose",l:"Цель"},{k:"host",l:"К кому"},{k:"kpp",l:"КПП"},{k:"timeIn",l:"Вход",r:v=><span style={{fontFamily:fm,fontWeight:600}}>{v}</span>},{k:"timeOut",l:"Выход",r:v=><span style={{fontFamily:fm,fontWeight:600}}>{v}</span>},{k:"sub",l:"Филиал",r:v=><Badge color={T.ac}>{v}</Badge>},{k:"status",l:"Статус",r:v=><Badge color={v==="inside"?T.sc:T.dm}>{v==="inside"?"На территории":"Вышел"}</Badge>}]} data={d} onRow={r=>setPanel({type:"visitorDetail",data:r})}/></div></div>);};

    const PassesPage=()=>{const [tab,setTab]=useState("all");const d=tab==="all"?passes:passes.filter(p=>p.status===tab);return(<div><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}><h1 style={{fontSize:22,fontWeight:800,fontFamily:fd,margin:0}}>Пропуска</h1><Btn icon="plus" onClick={()=>setPanel({type:"newPass"})}>Создать заявку</Btn></div><div style={{display:"flex",gap:5,marginBottom:12}}>{[{v:"all",l:"Все "+passes.length},{v:"pending",l:"Ожидают "+passes.filter(p=>p.status==="pending").length},{v:"approved",l:"Согласованы "+passes.filter(p=>p.status==="approved").length},{v:"rejected",l:"Отклонены "+passes.filter(p=>p.status==="rejected").length}].map(f=><button key={f.v} onClick={()=>setTab(f.v)} style={{padding:"5px 12px",borderRadius:6,border:"1px solid "+(tab===f.v?T.ac:T.bd),background:tab===f.v?T.acD:T.sf,color:tab===f.v?T.ac:T.mt,cursor:"pointer",fontSize:12,fontFamily:fb}}>{f.l}</button>)}</div><div style={{background:T.sf,border:"1px solid "+T.bd,borderRadius:10}}><Tbl cols={[{k:"id",l:"№",r:v=><span style={{fontFamily:fm,fontWeight:700}}>{v}</span>},{k:"type",l:"Тип",r:v=><Badge color={v==="visitor"?T.ac:T.sl}>{v==="visitor"?"Посетитель":"Техника"}</Badge>},{k:"visitor",l:"Посетитель",r:v=><span style={{fontWeight:600}}>{v}</span>},{k:"requester",l:"Заявитель",r:(v,r)=><div><div>{v}</div><div style={{fontSize:11,color:T.dm}}>{r.dept}</div></div>},{k:"sub",l:"Площадка",r:v=><Badge color={T.ac}>{v}</Badge>},{k:"status",l:"Статус",r:v=><Badge color={v==="pending"?T.wn:v==="approved"?T.sc:T.dn}>{v==="pending"?"Ожидает":v==="approved"?"Согласовано":"Отклонено"}</Badge>},{k:"_",l:"",r:(_,r)=>r.status==="pending"?<div style={{display:"flex",gap:3}}><Btn small v="success" icon="check" onClick={e=>{e.stopPropagation();approvPass(r.id);}}>Да</Btn><Btn small v="danger" icon="x" onClick={e=>{e.stopPropagation();rejectPass(r.id);}}>Нет</Btn></div>:null}]} data={d} onRow={r=>setPanel({type:"passDetail",data:r})}/></div></div>);};

    const InspectionPage=()=>{const [f,setF]=useState("all");const d=f==="all"?INSPECTIONS:f==="violation"?INSPECTIONS.filter(x=>x.status==="violation"):INSPECTIONS.filter(x=>x.inspType===f);return(<div><h1 style={{fontSize:22,fontWeight:800,fontFamily:fd,margin:"0 0 14px"}}>Досмотр</h1><div style={{display:"flex",gap:5,marginBottom:12}}>{[{v:"all",l:"Все "+INSPECTIONS.length},{v:"vehicle",l:"Авто"},{v:"person",l:"Физ.лица"},{v:"violation",l:"Нарушения"}].map(x=><button key={x.v} onClick={()=>setF(x.v)} style={{padding:"5px 12px",borderRadius:6,border:"1px solid "+(f===x.v?T.sl:T.bd),background:f===x.v?T.slD:T.sf,color:f===x.v?T.sl:T.mt,cursor:"pointer",fontSize:12,fontFamily:fb}}>{x.l}</button>)}</div><div style={{background:T.sf,border:"1px solid "+T.bd,borderRadius:10}}><Tbl cols={[{k:"plate",l:"Гос.номер",r:v=><span style={{fontFamily:fm,fontWeight:700}}>{v}</span>},{k:"driver",l:"Лицо"},{k:"vtype",l:"ТС"},{k:"inspType",l:"Тип",r:v=><Badge color={v==="vehicle"?T.sl:T.ac}>{v==="vehicle"?"Авто":"Физ.лицо"}</Badge>},{k:"time",l:"Время",r:v=><span style={{fontFamily:fm}}>{v}</span>},{k:"post",l:"КПП"},{k:"sub",l:"Площадка",r:v=><Badge color={T.ac}>{v}</Badge>},{k:"status",l:"Результат",r:v=><Badge color={v==="passed"?T.sc:T.dn}>{v==="passed"?"ОК":"Нарушение"}</Badge>}]} data={d} onRow={r=>setPanel({type:"inspDetail",data:r})}/></div></div>);};

    const TMCPage=()=>{const [f,setF]=useState("all");const d=f==="all"?TMC_DATA:f==="cargo"||f==="personal"?TMC_DATA.filter(t=>t.type===f):TMC_DATA.filter(t=>t.status===f);return(<div><h1 style={{fontSize:22,fontWeight:800,fontFamily:fd,margin:"0 0 14px"}}>ТМЦ и грузы</h1><div style={{display:"flex",gap:5,marginBottom:12}}>{[{v:"all",l:"Все"},{v:"cargo",l:"Грузы"},{v:"personal",l:"Личное"},{v:"on_site",l:"На территории"},{v:"removed",l:"Вывезено"}].map(x=><button key={x.v} onClick={()=>setF(x.v)} style={{padding:"5px 12px",borderRadius:6,border:"1px solid "+(f===x.v?T.pu:T.bd),background:f===x.v?T.puD:T.sf,color:f===x.v?T.pu:T.mt,cursor:"pointer",fontSize:12,fontFamily:fb}}>{x.l}</button>)}</div><div style={{background:T.sf,border:"1px solid "+T.bd,borderRadius:10}}><Tbl cols={[{k:"type",l:"Тип",r:v=><Badge color={v==="cargo"?T.sl:T.ac}>{v==="cargo"?"Груз":"Личное"}</Badge>},{k:"item",l:"Наименование",r:v=><span style={{fontWeight:600}}>{v}</span>},{k:"person",l:"Лицо"},{k:"dir",l:"Напр.",r:v=><span style={{color:v==="in"?T.sc:T.dn,fontWeight:600}}>{v==="in"?"→ Ввоз":"← Вывоз"}</span>},{k:"time",l:"Время",r:v=><span style={{fontFamily:fm}}>{v}</span>},{k:"sub",l:"Площадка",r:v=><Badge color={T.ac}>{v}</Badge>},{k:"status",l:"Статус",r:v=><Badge color={v==="on_site"?T.sc:T.dm}>{v==="on_site"?"На территории":"Вывезено"}</Badge>}]} data={d} onRow={r=>setPanel({type:"tmcDetail",data:r})}/></div></div>);};

    const DocumentsPage=()=>(<div><h1 style={{fontSize:22,fontWeight:800,fontFamily:fd,margin:"0 0 14px"}}>Документы охраны</h1><div style={{background:T.sf,border:"1px solid "+T.bd,borderRadius:10}}><Tbl cols={[{k:"name",l:"Название",r:v=><span style={{fontWeight:600}}>{v}</span>},{k:"category",l:"Категория",r:v=><Badge color={T.sl}>{v}</Badge>},{k:"date",l:"Дата",r:v=><span style={{fontFamily:fm}}>{v}</span>},{k:"author",l:"Автор"},{k:"sub",l:"Площадка",r:v=><Badge color={T.ac}>{v}</Badge>},{k:"status",l:"Статус",r:v=><Badge color={v==="active"?T.sc:T.dm}>{v==="active"?"Действующий":"Архив"}</Badge>}]} data={DOCS}/></div></div>);

    const HRPage=()=>{const [hrTab,setHrTab]=useState("staff");const days=["Пн 28","Вт 29","Ср 30","Чт 01","Пт 02","Сб 03","Вс 04"];const sc2={day:{bg:T.acD,c:T.ac,l:"День"},night:{bg:T.er+"12",c:T.er,l:"Ночь"},off:{bg:"transparent",c:T.dm,l:"—"}};const schedG=guardsData.slice(0,12).map((g,i)=>({...g,shifts:days.map((_,j)=>(["day","day","night","night","off","off","day"][(i+j)%7]))}));return(<div><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}><h1 style={{fontSize:22,fontWeight:800,fontFamily:fd,margin:0}}>HR и график дежурств</h1><Btn v="ghost" icon="sync" onClick={doSync} disabled={syncing}>{syncing?"Синхронизация...":"Синхронизация"}</Btn>{syncing&&<div style={{position:"fixed",inset:0,zIndex:2000,background:"rgba(30,26,22,0.6)",backdropFilter:"blur(4px)",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:16}}><div style={{width:56,height:56,border:"5px solid "+T.ac+"30",borderTop:"5px solid "+T.ac,borderRadius:"50%",animation:"spin 1s linear infinite"}}/><div style={{fontSize:18,fontWeight:700,color:"#FFF",fontFamily:fd}}>Синхронизация с 1С</div><div style={{fontSize:13,color:T.st}}>Загрузка данных...</div></div>}</div><div style={{display:"flex",gap:0,marginBottom:14,background:T.sf,border:"1px solid "+T.bd,borderRadius:8,padding:3}}>{[{id:"staff",l:"Сотрудники"},{id:"schedule",l:"График дежурств"}].map(t=><button key={t.id} onClick={()=>setHrTab(t.id)} style={{flex:1,padding:"8px",borderRadius:5,border:"none",background:hrTab===t.id?T.ac:"transparent",color:hrTab===t.id?"#FFF":T.mt,cursor:"pointer",fontSize:13,fontFamily:fb,fontWeight:hrTab===t.id?700:500}}>{t.l}</button>)}</div>{hrTab==="staff"&&<div style={{background:T.sf,border:"1px solid "+T.bd,borderRadius:10}}><Tbl cols={[{k:"name",l:"ФИО",r:v=><span style={{fontWeight:600}}>{v}</span>},{k:"position",l:"Должность"},{k:"shift",l:"Смена",r:v=><Badge color={v==="Дневная"?T.ac:T.er}>{v}</Badge>},{k:"status",l:"Статус",r:v=><span style={{display:"flex",alignItems:"center",gap:4}}><Dot color={{on_duty:T.sc,off_duty:T.dm,vacation:T.wn,sick:T.dn}[v]}/>{({on_duty:"На смене",off_duty:"Не на смене",vacation:"Отпуск",sick:"Больничный"})[v]}</span>},{k:"sub",l:"Площадка",r:v=><Badge color={T.ac}>{v}</Badge>},{k:"phone",l:"Телефон",r:v=><span style={{fontFamily:fm,fontSize:12}}>{v}</span>}]} data={guardsData}/></div>}{hrTab==="schedule"&&<div style={{background:T.sf,border:"1px solid "+T.bd,borderRadius:10,overflow:"auto"}}><table style={{width:"100%",borderCollapse:"collapse"}}><thead><tr><th style={{textAlign:"left",padding:"9px 10px",fontSize:10,fontFamily:fm,color:T.dm,borderBottom:"2px solid "+T.bd,background:T.bg}}>СОТРУДНИК</th><th style={{textAlign:"left",padding:"9px 8px",fontSize:10,fontFamily:fm,color:T.dm,borderBottom:"2px solid "+T.bd,background:T.bg}}>ПЛОЩ.</th>{days.map(d=><th key={d} style={{textAlign:"center",padding:"9px 3px",fontSize:11,fontFamily:fm,color:d.includes("01")?T.ac:T.dm,borderBottom:"2px solid "+T.bd,background:d.includes("01")?T.acD:T.bg,fontWeight:600}}>{d}</th>)}</tr></thead><tbody>{schedG.map((g,i)=><tr key={i}><td style={{padding:"8px 10px",fontSize:13,fontWeight:600,borderBottom:"1px solid "+T.bdL}}>{g.name}</td><td style={{padding:"8px 8px",borderBottom:"1px solid "+T.bdL}}><Badge color={T.ac}>{g.sub}</Badge></td>{g.shifts.map((s,j)=><td key={j} style={{textAlign:"center",padding:3,borderBottom:"1px solid "+T.bdL}}><span style={{display:"inline-block",padding:"3px 9px",borderRadius:4,background:sc2[s].bg,color:sc2[s].c,fontSize:10,fontFamily:fm,fontWeight:600}}>{sc2[s].l}</span></td>)}</tr>)}</tbody></table></div>}</div>);};

    const SettingsPage=()=>{
        const moveUp=(i)=>{if(i===0)return;setApprovers(prev=>{const a=[...prev];const tmp=a[i-1];a[i-1]=a[i];a[i]=tmp;return a;});showToast("Порядок изменён");};
        const moveDown=(i)=>{setApprovers(prev=>{if(i>=prev.length-1)return prev;const a=[...prev];const tmp=a[i];a[i]=a[i+1];a[i+1]=tmp;return a;});showToast("Порядок изменён");};
        const addStep=(name)=>{setApprovers(prev=>[...prev,{id:Date.now(),name,role:"Согласующий"}]);setShowAddStep(false);showToast("Этап добавлен");};
        const removeStep=(id)=>{setApprovers(prev=>prev.filter(a=>a.id!==id));showToast("Этап удалён","danger");};
        const available=APPROVER_POOL.filter(n=>!approvers.find(a=>a.name===n));
        return(<div><h1 style={{fontSize:22,fontWeight:800,fontFamily:fd,margin:"0 0 14px"}}>Настройки</h1><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
            <div style={{background:T.sf,border:"1px solid "+T.bd,borderRadius:10,padding:16}}>
                <h3 style={{margin:"0 0 4px",fontSize:14,fontFamily:fd,fontWeight:700}}>Маршрут согласования</h3>
                <p style={{fontSize:11,color:T.mt,marginBottom:14,marginTop:0}}>Используйте стрелки ▲▼ для изменения порядка</p>
                {approvers.map((a,i)=>(
                    <div key={a.id} style={{display:"flex",alignItems:"center",gap:8,padding:"10px 12px",background:T.bg,borderRadius:7,marginBottom:6,border:"1px solid "+T.bd}}>
                        <div style={{display:"flex",flexDirection:"column",gap:2}}>
                            <button onClick={()=>moveUp(i)} style={{background:"none",border:"none",cursor:i===0?"default":"pointer",padding:0,opacity:i===0?0.2:1,fontSize:14,lineHeight:"1"}}>▲</button>
                            <button onClick={()=>moveDown(i)} style={{background:"none",border:"none",cursor:i>=approvers.length-1?"default":"pointer",padding:0,opacity:i>=approvers.length-1?0.2:1,fontSize:14,lineHeight:"1"}}>▼</button>
                        </div>
                        <div style={{width:24,height:24,borderRadius:6,background:T.ac+"15",display:"flex",alignItems:"center",justifyContent:"center",fontSize:12,fontWeight:700,color:T.ac,fontFamily:fm}}>{i+1}</div>
                        <div style={{flex:1}}><div style={{fontSize:13,fontWeight:600}}>{a.name}</div><div style={{fontSize:10,color:T.mt}}>{a.role}</div></div>
                        <button onClick={()=>removeStep(a.id)} style={{background:T.dnD,border:"1px solid "+T.dn+"25",borderRadius:5,cursor:"pointer",padding:"3px 8px",fontSize:11,color:T.dn,fontFamily:fb}}>✕ Убрать</button>
                    </div>
                ))}
                {showAddStep?<div style={{border:"2px solid "+T.ac,borderRadius:8,padding:10,marginTop:8,background:T.acD}}>
                        <div style={{fontSize:12,fontWeight:700,color:T.ac,marginBottom:8}}>Выберите этап для добавления:</div>
                        {available.length>0?available.map(n=><button key={n} onClick={()=>addStep(n)} style={{display:"block",width:"100%",padding:"10px 12px",background:T.sf,borderRadius:6,marginBottom:4,cursor:"pointer",fontSize:14,fontWeight:500,border:"1px solid "+T.bdL,textAlign:"left",fontFamily:fb,color:T.tx}}>{n}</button>):<div style={{padding:10,color:T.mt,fontSize:13}}>Все доступные этапы уже добавлены</div>}
                        <button onClick={()=>setShowAddStep(false)} style={{width:"100%",padding:"8px",border:"1px solid "+T.bd,borderRadius:6,background:T.sf,cursor:"pointer",fontSize:12,color:T.mt,marginTop:6,fontFamily:fb}}>Отмена</button>
                    </div>
                    :<button onClick={()=>setShowAddStep(true)} style={{width:"100%",padding:"10px",border:"2px dashed "+T.ac,borderRadius:8,background:T.acD,cursor:"pointer",fontSize:13,color:T.ac,fontFamily:fb,fontWeight:600,marginTop:6,display:"flex",alignItems:"center",justifyContent:"center",gap:6}}><Icon name="plus" size={16} color={T.ac}/> Добавить этап согласования</button>}
            </div>
            <div style={{display:"flex",flexDirection:"column",gap:14}}>{[{title:"КПП",items:["КПП-1 Главный","КПП-2 Карьерный","КПП-3 Склад ГСМ","КПП-4 Фабрика"]},{title:"Роли и доступ",items:["Администратор","Начальник СБ","Специалист СБ","Охранник КПП","Заявитель (ИТР)"]},{title:"Интеграции",items:["1С:ЗУП — ✓","СКУД Бастион-3 — ✓","GPS мониторинг — ✓","Складской учёт — ⚠"]}].map((s,i)=><div key={i} style={{background:T.sf,border:"1px solid "+T.bd,borderRadius:10,padding:14}}><h3 style={{margin:"0 0 8px",fontSize:13,fontFamily:fd,fontWeight:700}}>{s.title}</h3>{s.items.map((item,j)=><div key={j} style={{padding:"7px 10px",background:T.bg,borderRadius:5,marginBottom:3,fontSize:12,color:T.ts,display:"flex",justifyContent:"space-between",border:"1px solid "+T.bdL}}><span>{item}</span><Icon name="settings" size={12} color={T.dm}/></div>)}</div>)}</div>
        </div></div>);};

    const CCTVPage=()=>{const cams=[{id:1,name:"КПП-1 Главный въезд"},{id:2,name:"КПП-2 Карьер"},{id:3,name:"КПП-3 Склад ГСМ"},{id:4,name:"Периметр — сектор А"},{id:5,name:"Фабрика — вход"},{id:6,name:"Стоянка техники"}];const videoUrl="https://drive.google.com/file/d/11frpvM3x0C8fckE9jY4dcCxX7vcQliBi/preview";return(<div><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}><div><h1 style={{fontSize:22,fontWeight:800,fontFamily:fd,margin:0}}>Видеонаблюдение</h1><p style={{fontSize:12,color:T.mt,margin:"4px 0 0"}}>Камеры объектов в реальном времени</p></div><div style={{display:"flex",alignItems:"center",gap:6,padding:"5px 12px",background:T.scD,borderRadius:6}}><Dot color={T.sc}/><span style={{fontSize:12,color:T.sc,fontWeight:600}}>6 камер онлайн</span></div></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:12}}>{cams.map(cam=><div key={cam.id} style={{background:T.sf,border:"1px solid "+T.bd,borderRadius:10,overflow:"hidden"}}><div style={{position:"relative",paddingBottom:"56.25%",background:"#111"}}><iframe src={videoUrl} style={{position:"absolute",top:0,left:0,width:"100%",height:"100%",border:"none"}} allow="autoplay; encrypted-media" allowFullScreen/></div><div style={{padding:"10px 12px",display:"flex",alignItems:"center",justifyContent:"space-between"}}><div style={{display:"flex",alignItems:"center",gap:6}}><Dot color={T.sc}/><span style={{fontSize:12,fontWeight:600}}>{cam.name}</span></div><span style={{fontSize:10,color:T.dm,fontFamily:fm}}>LIVE</span></div></div>)}</div></div>);};

    const pageMap={dashboard:DashboardPage,visitors:VisitorsPage,passes:PassesPage,inspection:InspectionPage,tmc:TMCPage,cctv:CCTVPage,documents:DocumentsPage,hr:HRPage,settings:SettingsPage};
    const P=pageMap[page]||DashboardPage;

    const renderPanel=()=>{if(!panel)return null;const {type,data}=panel;
        if(type==="newPass")return(<SlideOver title="Новая заявка на пропуск" onClose={()=>setPanel(null)} wide><Inp label="Тип заявки" select options={[{v:"visitor",l:"Посетитель"},{v:"vehicle",l:"Транспорт"},{v:"contractor",l:"Подрядчик"}]} value="visitor" onChange={()=>{}}/><div style={{display:"flex",gap:10}}><Inp half label="Структурное подразделение" select options={depts.map(d=>({v:d,l:d}))} value={depts[0]} onChange={()=>{}}/><Inp half label="Цель визита" placeholder="До 100 символов" value="" onChange={()=>{}}/></div><Inp label="Подтверждающие документы" file/><div style={{display:"flex",gap:10}}><Inp half label="Сопровождающее лицо" select options={names.slice(0,10).map(n=>({v:n,l:n}))} value={names[0]} onChange={()=>{}}/><Inp half label="Телефон сопровождающего" placeholder="+7 701 000 0000" value="" onChange={()=>{}}/></div><div style={{display:"flex",gap:10}}><Inp half label="Этаж / помещение" placeholder="2 этаж, каб. 205" value="" onChange={()=>{}}/><Inp half label="Согласующий" select options={names.slice(10,18).map(n=>({v:n,l:n}))} value={names[10]} onChange={()=>{}}/></div><div style={{display:"flex",gap:10}}><Inp half label="Дата входа с" type="date" value="2026-05-01" onChange={()=>{}}/><Inp half label="Дата входа по" type="date" value="2026-05-15" onChange={()=>{}}/></div><div style={{background:T.acD,border:"1px solid "+T.ac+"25",borderRadius:8,padding:12,marginBottom:14}}><div style={{fontSize:11,fontWeight:700,color:T.ac,marginBottom:8}}>Данные посетителя</div><div style={{display:"flex",gap:10}}><Inp half label="ФИО посетителя" placeholder="Иванов Пётр Сергеевич" value="" onChange={()=>{}}/><Inp half label="ИИН / Номер паспорта" placeholder="850412301245" value="" onChange={()=>{}}/></div></div><div style={{background:T.puD,border:"1px solid "+T.pu+"25",borderRadius:8,padding:12,marginBottom:14}}><div style={{fontSize:11,fontWeight:700,color:T.pu,marginBottom:8}}>ТМЦ</div><div style={{display:"flex",gap:6}}><input placeholder="Название предмета" style={{flex:1,padding:"7px 10px",border:"1px solid "+T.pu+"25",borderRadius:5,fontSize:13,fontFamily:fb,outline:"none",background:T.sf}}/><Btn small icon="plus">Добавить</Btn></div></div><div style={{display:"flex",gap:8,justifyContent:"flex-end"}}><Btn v="ghost" onClick={()=>setPanel(null)}>Отмена</Btn><Btn icon="check" onClick={()=>{setPanel(null);showToast("Заявка отправлена");}}>Отправить</Btn></div></SlideOver>);
        if(type==="passDetail")return(<SlideOver title={"Заявка "+data.id} onClose={()=>setPanel(null)} wide><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:14}}>{[["Тип",data.type==="visitor"?"Посетитель":"Техника"],["Заявитель",data.requester],["Подразделение",data.dept],["Посетитель",data.visitor],["ИИН",data.iin],["Цель",data.purpose],["Сопровождающий",data.host],["Телефон",data.hostPhone],["Этаж",data.floor],["Согласующий",data.approver],["Дата с",data.dateFrom],["Дата по",data.dateTo],["Площадка",data.sub]].map(([l,v],i)=><div key={i}><div style={{fontSize:10,color:T.dm,fontFamily:fm,textTransform:"uppercase",marginBottom:2}}>{l}</div><div style={{fontSize:14,fontWeight:600}}>{v}</div></div>)}</div>{data.tmc.length>0&&<div style={{background:T.puD,border:"1px solid "+T.pu+"25",borderRadius:7,padding:10,marginBottom:12}}><div style={{fontSize:10,fontWeight:700,color:T.pu,marginBottom:4}}>ТМЦ</div>{data.tmc.map((t,i)=><div key={i} style={{fontSize:13,padding:"2px 0"}}>{i+1}. {t}</div>)}</div>}<div style={{border:"1px solid "+T.bd,borderRadius:8,padding:12,marginBottom:14,background:T.bg}}><div style={{display:"flex",alignItems:"center",gap:8,marginBottom:10}}><Icon name="idcard" size={16} color={T.sl}/><span style={{fontSize:11,fontWeight:700,color:T.sl,fontFamily:fm,textTransform:"uppercase"}}>Приложенный документ</span></div><img src={IDCARD} style={{width:"100%",borderRadius:6,border:"1px solid "+T.bdL}} alt="Удостоверение личности"/></div>{data.status==="pending"&&<div style={{display:"flex",gap:8,marginTop:14}}><Btn v="success" icon="check" onClick={()=>{approvPass(data.id);setPanel(null);}} style={{flex:1,justifyContent:"center"}}>Согласовать</Btn><Btn v="danger" icon="x" onClick={()=>{rejectPass(data.id);setPanel(null);}} style={{flex:1,justifyContent:"center"}}>Отклонить</Btn></div>}{data.status!=="pending"&&<div style={{marginTop:12,padding:10,borderRadius:7,background:data.status==="approved"?T.scD:T.dnD,textAlign:"center"}}><Badge color={data.status==="approved"?T.sc:T.dn}>{data.status==="approved"?"СОГЛАСОВАНО":"ОТКЛОНЕНО"}</Badge></div>}</SlideOver>);
        if(type==="visitorDetail")return(<SlideOver title={"Посетитель — "+data.name} onClose={()=>setPanel(null)}><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>{[["ФИО",data.name],["ИИН",data.iin],["Организация",data.company],["Цель визита",data.purpose],["К кому",data.host],["КПП",data.kpp],["Вход",data.timeIn],["Выход",data.timeOut],["Филиал",data.sub]].map(([l,v],i)=><div key={i}><div style={{fontSize:10,color:T.dm,fontFamily:fm,textTransform:"uppercase",marginBottom:2}}>{l}</div><div style={{fontSize:14,fontWeight:600}}>{v}</div></div>)}</div><div style={{border:"1px solid "+T.bd,borderRadius:8,padding:12,marginTop:16,marginBottom:14,background:T.bg}}><div style={{display:"flex",alignItems:"center",gap:8,marginBottom:10}}><Icon name="idcard" size={16} color={T.sl}/><span style={{fontSize:11,fontWeight:700,color:T.sl,fontFamily:fm,textTransform:"uppercase"}}>Приложенный документ</span></div><img src={IDCARD} style={{width:"100%",borderRadius:6,border:"1px solid "+T.bdL}} alt="Удостоверение"/></div><div style={{padding:12,borderRadius:8,background:data.status==="inside"?T.scD:T.bg,textAlign:"center"}}><Badge color={data.status==="inside"?T.sc:T.dm}>{data.status==="inside"?"На территории":"Покинул территорию"}</Badge></div></SlideOver>);
        if(type==="inspDetail")return(<SlideOver title={"Досмотр — "+(data.plate!=="—"?data.plate:data.driver)} onClose={()=>setPanel(null)}><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>{[["Гос. номер",data.plate],["Тип ТС",data.vtype],["Водитель / Лицо",data.driver],["Тип досмотра",data.inspType==="vehicle"?"Авто":"Физ. лицо"],["КПП",data.post],["Время",data.time],["Площадка",data.sub],["Результат",data.status==="passed"?"Без нарушений":"Нарушение"],["Примечание",data.notes]].map(([l,v],i)=><div key={i}><div style={{fontSize:10,color:T.dm,fontFamily:fm,textTransform:"uppercase",marginBottom:2}}>{l}</div><div style={{fontSize:14,fontWeight:600,color:l==="Результат"?(data.status==="passed"?T.sc:T.dn):T.tx}}>{v}</div></div>)}</div>{data.status==="violation"&&<div style={{marginTop:16,padding:12,borderRadius:8,background:T.dnD,textAlign:"center"}}><Badge color={T.dn}>НАРУШЕНИЕ</Badge></div>}</SlideOver>);
        if(type==="tmcDetail")return(<SlideOver title={"ТМЦ — "+data.item} onClose={()=>setPanel(null)}><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>{[["Наименование",data.item],["Тип",data.type==="cargo"?"Груз":"Личное имущество"],["Лицо",data.person],["Направление",data.dir==="in"?"Ввоз/Внос":"Вывоз/Вынос"],["Время",data.time],["Площадка",data.sub],["Статус",data.status==="on_site"?"На территории":"Вывезено/Вынесено"]].map(([l,v],i)=><div key={i}><div style={{fontSize:10,color:T.dm,fontFamily:fm,textTransform:"uppercase",marginBottom:2}}>{l}</div><div style={{fontSize:14,fontWeight:600}}>{v}</div></div>)}</div></SlideOver>);
        return null;};

    return(<div style={{display:"flex",height:"100vh",background:T.bg,color:T.tx,fontFamily:fb,overflow:"hidden"}}><style>{CSS}</style>
        <div style={{width:collapsed?60:220,background:"linear-gradient(180deg,#2C2420,#1E1A16)",display:"flex",flexDirection:"column",transition:"width 0.25s",overflow:"hidden",flexShrink:0}}><div style={{padding:collapsed?"14px 8px":"14px 12px",display:"flex",alignItems:"center",gap:8,borderBottom:"1px solid rgba(255,255,255,0.06)"}}><img src={LOGO} width={28} height={28} style={{objectFit:"contain",flexShrink:0}} alt=""/>{!collapsed&&<div><div style={{fontSize:13,fontWeight:800,color:"#F0EBE4",fontFamily:fd}}>Polymetal СБ</div><div style={{fontSize:9,color:T.st,fontFamily:fm}}>СЛУЖБА БЕЗОПАСНОСТИ</div></div>}</div><div style={{flex:1,padding:"6px 4px"}}>{navItems.map(it=>{const act=page===it.id;return<button key={it.id} onClick={()=>setPage(it.id)} style={{display:"flex",alignItems:"center",gap:8,width:"100%",padding:"7px 9px",background:act?T.sa:"transparent",border:act?"1px solid "+T.ac+"30":"1px solid transparent",borderRadius:6,cursor:"pointer",marginBottom:2,justifyContent:collapsed?"center":"flex-start"}} onMouseEnter={e=>{if(!act)e.currentTarget.style.background="rgba(255,255,255,0.04)"}} onMouseLeave={e=>{e.currentTarget.style.background=act?T.sa:"transparent"}}><Icon name={it.icon} size={15} color={act?T.ac:T.st}/>{!collapsed&&<span style={{fontSize:12,fontFamily:fb,color:act?"#F0EBE4":T.st,fontWeight:act?600:400,whiteSpace:"nowrap"}}>{it.label}</span>}</button>;})}</div><div style={{padding:"6px 4px",borderTop:"1px solid rgba(255,255,255,0.06)"}}><button onClick={()=>{setAuth(null);setAuthStep("form");}} style={{display:"flex",alignItems:"center",gap:8,width:"100%",padding:"7px 9px",background:"transparent",border:"none",borderRadius:6,cursor:"pointer",justifyContent:collapsed?"center":"flex-start"}}><Icon name="logout" size={15} color={T.st}/>{!collapsed&&<span style={{fontSize:12,color:T.st,fontFamily:fb}}>Выход</span>}</button></div></div>
        <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}><div style={{height:48,background:T.sf,borderBottom:"1px solid "+T.bd,display:"flex",alignItems:"center",justifyContent:"space-between",padding:"0 16px",flexShrink:0}}><div style={{display:"flex",alignItems:"center",gap:8}}><button onClick={()=>setCol(!collapsed)} style={{background:"none",border:"none",cursor:"pointer",padding:2}}><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={T.mt} strokeWidth="2"><line x1="3" y1="6" x2="21" y2="6"/><line x1="3" y1="12" x2="21" y2="12"/><line x1="3" y1="18" x2="21" y2="18"/></svg></button><div style={{display:"flex",alignItems:"center",gap:5,background:T.bg,border:"1px solid "+T.bd,borderRadius:7,padding:"5px 10px",width:180}}><Icon name="search" size={13} color={T.dm}/><span style={{color:T.dm,fontSize:11}}>Поиск...</span></div></div><div style={{display:"flex",alignItems:"center",gap:8}}><div style={{display:"flex",alignItems:"center",gap:3,padding:"2px 6px",background:T.scD,borderRadius:4}}><Dot color={T.sc}/><span style={{fontSize:9,color:T.sc,fontFamily:fm,fontWeight:600}}>ONLINE</span></div><button style={{background:T.bg,border:"1px solid "+T.bd,borderRadius:6,cursor:"pointer",padding:4,display:"flex",position:"relative"}}><Icon name="bell" size={14} color={T.mt}/><span style={{position:"absolute",top:1,right:1,width:5,height:5,borderRadius:"50%",background:T.dn,border:"1.5px solid "+T.sf}}/></button><div style={{display:"flex",alignItems:"center",gap:5}}><div style={{width:26,height:26,borderRadius:7,background:"linear-gradient(135deg,"+T.ac+","+T.er+")",display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,fontWeight:700,color:"#FFF",fontFamily:fd}}>АК</div><div><div style={{fontSize:11,fontWeight:700}}>Ахметов К.Б.</div><div style={{fontSize:9,color:T.mt}}>Нач. СБ</div></div></div></div></div><div style={{flex:1,overflow:"auto",padding:18}}><P/></div></div>
        {renderPanel()}<Toast/>
    </div>);
}